import sys
from collections import deque

def solve():
    sys.setrecursionlimit(1_000_000)
    input = sys.stdin.readline

    H, W, T = map(int, input().split())
    grid = [list(input().strip()) for _ in range(H)]

    si = sj = gi = gj = -1
    candies = []
    for i in range(H):
        for j in range(W):
            c = grid[i][j]
            if c == 'S':
                si, sj = i, j
            elif c == 'G':
                gi, gj = i, j
            elif c == 'o':
                candies.append((i, j))

    C = len(candies)
    if C == 0:
        # Just check reachability within T
        dist = [[-1] * W for _ in range(H)]
        dq = deque([(si, sj)])
        dist[si][sj] = 0
        dirs = [(1,0),(-1,0),(0,1),(0,-1)]
        while dq:
            x, y = dq.popleft()
            for dx, dy in dirs:
                nx, ny = x + dx, y + dy
                if 0 <= nx < H and 0 <= ny < W and grid[nx][ny] != '#':
                    if dist[nx][ny] == -1:
                        dist[nx][ny] = dist[x][y] + 1
                        dq.append((nx, ny))
        d = dist[gi][gj]
        if d == -1 or d > T:
            print(-1)
        else:
            print(0)
        return

    # BFS from each special point (S, candies, G) to get pairwise shortest distances
    points = [(si, sj)] + candies + [(gi, gj)]
    P = 1 + C + 1

    def bfs_from(src):
        sx, sy = src
        dist = [[-1] * W for _ in range(H)]
        dq = deque([(sx, sy)])
        dist[sx][sy] = 0
        dirs = [(1,0),(-1,0),(0,1),(0,-1)]
        while dq:
            x, y = dq.popleft()
            for dx, dy in dirs:
                nx, ny = x + dx, y + dy
                if 0 <= nx < H and 0 <= ny < W and grid[nx][ny] != '#':
                    if dist[nx][ny] == -1:
                        dist[nx][ny] = dist[x][y] + 1
                        dq.append((nx, ny))
        return dist

    dists = []
    for p in points:
        dmat = bfs_from(p)
        dists.append(dmat)

    INF = 10**18

    # Build distance matrix between special points
    dist_sp = [[INF] * P for _ in range(P)]
    for i in range(P):
        xi, yi = points[i]
        for j in range(P):
            xj, yj = points[j]
            d = dists[i][xj][yj]
            if d != -1:
                dist_sp[i][j] = d

    # Quick feasibility: if even shortest S->G > T then impossible (but DP will also handle)
    if dist_sp[0][P-1] > T:
        print(-1)
        return

    # DP over subsets of candies: dp[mask][last] = min moves to start at S,
    # visit candies in mask, and end at candy last (index in 0..C-1),
    # where "last" is included in mask.
    # Complexity: O( C^2 * 2^C ) with C<=18 => OK.
    size = 1 << C
    dp = [[INF] * C for _ in range(size)]

    # Initialize transitions from S to each reachable candy
    for i in range(C):
        d = dist_sp[0][1 + i]
        if d != INF:
            dp[1 << i][i] = d

    # Transitions among candies
    for mask in range(size):
        for last in range(C):
            if not (mask & (1 << last)):
                continue
            cur = dp[mask][last]
            if cur == INF:
                continue
            for nxt in range(C):
                if mask & (1 << nxt):
                    continue
                nd = dist_sp[1 + last][1 + nxt]
                if nd == INF:
                    continue
                nmask = mask | (1 << nxt)
                val = cur + nd
                if val < dp[nmask][nxt]:
                    dp[nmask][nxt] = val

    # Also allow masks empty? We can visit 0 candies: just check S->G.
    best = -1
    if dist_sp[0][P-1] <= T:
        best = 0

    # For each state ending at a candy, add distance to G
    for mask in range(size):
        cnt = mask.bit_count()
        if cnt <= best:
            # cannot beat best in count, but might still if best=-1; handle already
            pass
        for last in range(C):
            if not (mask & (1 << last)):
                continue
            cur = dp[mask][last]
            if cur == INF:
                continue
            to_goal = dist_sp[1 + last][P - 1]
            if to_goal == INF:
                continue
            total = cur + to_goal
            if total <= T:
                if cnt > best:
                    best = cnt

    print(best)

if __name__ == "__main__":
    solve()
